  AND pv.sessions_per_week = 4
ON CONFLICT DO NOTHING;

-- Variant: Outdoor Adventure Fitness - 8w 5x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    8,
    'Outdoor Adventure Fitness - 8w 5x/wk',
    'outdoor',
    5,
    60,
    ARRAY['Build cardiovascular endurance', 'Improve VO2 max']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Outdoor Adventure Fitness'
ON CONFLICT DO NOTHING;

